package main

import (
	"context"
	"fmt"
	"log"
	"net"
	"time"

	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/keepalive"
	"google.golang.org/grpc/status"
	pb "your/proto/package"
)

type server struct {
	pb.UnimplementedYourServiceServer
}

func main() {
	lis, err := net.Listen("tcp", ":50051")
	if err != nil {
		log.Fatalf("failed to listen: %v", err)
	}

	// Critical DoS mitigations
	s := grpc.NewServer(
		// Limit concurrent streams per connection (CRITICAL - prevents CVE-2023-44487)
		grpc.MaxConcurrentStreams(100), // Default is unlimited - MUST set this!

		// Additional HTTP/2 protections
		grpc.MaxRecvMsgSize(4 * 1024 * 1024),    // 4MB max message size
		grpc.MaxSendMsgSize(4 * 1024 * 1024),    // 4MB max message size
		grpc.MaxHeaderListSize(8 * 1024),        // 8KB max headers (prevents HPACK bomb)
		grpc.ConnectionTimeout(120 * time.Second), // Max connection duration

		// Keepalive enforcement (prevents keepalive abuse)
		grpc.KeepaliveEnforcementPolicy(keepalive.EnforcementPolicy{
			MinTime:             5 * time.Second, // Client must wait 5s between pings
			PermitWithoutStream: false,           // Require active stream for pings
		}),

		// Server-side keepalive parameters
		grpc.KeepaliveParams(keepalive.ServerParameters{
			MaxConnectionIdle:     15 * time.Minute, // Close idle connections
			MaxConnectionAge:      30 * time.Minute, // Max connection lifetime
			MaxConnectionAgeGrace: 5 * time.Second,  // Grace period before forced close
			Time:                  5 * time.Second,  // Ping interval
			Timeout:               1 * time.Second,  // Ping timeout
		}),

		// Connection limiting via interceptor
		grpc.ChainStreamInterceptor(
			streamRateLimitInterceptor(1000), // Max 1000 stream opens per second
		),
	)

	pb.RegisterYourServiceServer(s, &server{})

	log.Printf("gRPC server listening on :50051 with DoS protections")
	if err := s.Serve(lis); err != nil {
		log.Fatalf("failed to serve: %v", err)
	}
}

// Rate limit stream creation to prevent rapid reset attacks
func streamRateLimitInterceptor(maxPerSecond int) grpc.StreamServerInterceptor {
	type streamKey struct{}
	var (
		mu       sync.Mutex
		counter  int
		lastReset = time.Now()
	)

	return func(srv interface{}, ss grpc.ServerStream, info *grpc.StreamServerInfo, handler grpc.StreamHandler) error {
		mu.Lock()
		if time.Since(lastReset) > time.Second {
			counter = 0
			lastReset = time.Now()
		}
		counter++
		if counter > maxPerSecond {
			mu.Unlock()
			return status.Errorf(codes.ResourceExhausted, "stream rate limit exceeded")
		}
		mu.Unlock()

		return handler(srv, ss)
	}
}

const grpc = require('@grpc/grpc-js');
const protoLoader = require('@grpc/proto-loader');
const RateLimiter = require('limiter').RateLimiter;

// Load proto file
const packageDefinition = protoLoader.loadSync('service.proto', {
  keepCase: true,
  longs: String,
  enums: String,
  defaults: true,
  oneofs: true
});
const serviceProto = grpc.loadPackageDefinition(packageDefinition).yourpackage;

// Per-client rate limiters
const rateLimiters = new Map();
const RATE_LIMIT_PER_IP = 100; // requests per second
const MAX_CONCURRENT_STREAMS = 100;

// gRPC service implementation
const server = new grpc.Server({
  // HTTP/2 settings (critical for DoS prevention)
  'grpc.max_concurrent_streams': MAX_CONCURRENT_STREAMS,
  'grpc.max_receive_message_length': 4 * 1024 * 1024, // 4MB
  'grpc.max_send_message_length': 4 * 1024 * 1024,    // 4MB
  'grpc.max_connection_idle_ms': 300000,              // 5 minutes
  'grpc.max_connection_age_ms': 1800000,              // 30 minutes
  'grpc.max_connection_age_grace_ms': 5000,           // 5 seconds
  'grpc.http2.min_time_between_pings_ms': 5000,      // 5 seconds between pings
  'grpc.http2.max_pings_without_data': 2,             // Max pings without data
  'grpc.keepalive_time_ms': 7200000,                  // 2 hours
  'grpc.keepalive_timeout_ms': 20000,                 // 20 seconds

  // Additional security settings
  'grpc.max_metadata_size': 8 * 1024, // 8KB max metadata (prevents HPACK bomb)
  'grpc.initial_reconnect_backoff_ms': 1000,
  'grpc.max_reconnect_backoff_ms': 120000
});

// Rate limiting interceptor
function rateLimitInterceptor(methodDescriptor, call) {
  const clientIp = call.getPeer(); // Format: "ipv4:192.168.1.1:12345"
  const ip = clientIp.split(':')[1];

  // Create rate limiter for this IP if it doesn't exist
  if (!rateLimiters.has(ip)) {
    rateLimiters.set(ip, new RateLimiter({
      tokensPerInterval: RATE_LIMIT_PER_IP,
      interval: 'second'
    }));
  }

  const limiter = rateLimiters.get(ip);

  // Check rate limit
  if (!limiter.tryRemoveTokens(1)) {
    const error = new Error('Rate limit exceeded');
    error.code = grpc.status.RESOURCE_EXHAUSTED;
    error.metadata = new grpc.Metadata();
    error.metadata.add('retry-after', '1');
    throw error;
  }

  return call;
}

// Apply interceptor to all methods
server.addService(serviceProto.YourService.service, {
  YourMethod: (call, callback) => {
    try {
      rateLimitInterceptor(null, call);

      // Your actual RPC implementation
      callback(null, { message: 'Success' });
    } catch (error) {
      callback(error);
    }
  },

  // Streaming RPC with additional protection
  YourStreamingMethod: (call) => {
    try {
      rateLimitInterceptor(null, call);

      let messageCount = 0;
      const MAX_MESSAGES_PER_STREAM = 10000;

      call.on('data', (request) => {
        messageCount++;

        // Prevent infinite streaming DoS
        if (messageCount > MAX_MESSAGES_PER_STREAM) {
          call.destroy(new Error('Stream message limit exceeded'));
          return;
        }

        // Process message
        call.write({ response: 'processed' });
      });

      call.on('end', () => {
        call.end();
      });

      call.on('error', (error) => {
        console.error('Stream error:', error);
      });
    } catch (error) {
      call.destroy(error);
    }
  }
});

// Cleanup old rate limiters every 5 minutes
setInterval(() => {
  if (rateLimiters.size > 10000) {
    rateLimiters.clear();
  }
}, 300000);

server.bindAsync(
  '0.0.0.0:50051',
  grpc.ServerCredentials.createInsecure(),
  (error, port) => {
    if (error) {
      console.error('Failed to start server:', error);
      return;
    }
    console.log(`gRPC server with DoS protections listening on port ${port}`);
    server.start();
  }
);
